/**
 * Подтема SddsSbComTheme.Inverse
 */
@Composable
public fun SddsSbComTheme.Inverse(
    isDark: Boolean = isSystemInDarkTheme(),
    content: @Composable
    () -> Unit,
) {
    val colors = if (isDark) {
        darkInverseColors
    } else {
        lightInverseColors
    }
    val gradients = if (isDark) {
        darkInverseGradients
    } else {
        lightInverseGradients
    }
    SddsSbComTheme(
        colors = colors,
        gradients = gradients,
        content = content,
    )
}
